  "test-website/script.js": "document.addEventListener('DOMContentLoaded', function() {
    // Initialize countdown timer
    initializeCountdown();
});

function initializeCountdown() {
    const countdownPlaceholders = document.querySelectorAll('[data-countdown]');
    countdownPlaceholders.forEach(placeholder => {
        const targetDate = new Date(placeholder.dataset.countdown);

        function updateCountdown() {
            const now = new Date();
            const diff = targetDate - now;

            if (diff <= 0) {
                placeholder.textContent = 'Event Started!';
                return;
            }

            const days = Math.floor(diff / (1000 * 60 * 60 * 24));
            const hours = Math.floor((diff % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
            const seconds = Math.floor((diff % (1000 * 60)) / 1000);

            placeholder.innerHTML = `
                <div>Opening in:</div>
                <div class="countdown-numbers">
                    <span>${days}d</span>
                    <span>${hours}h</span>
                    <span>${minutes}m</span>
                    <span>${seconds}s</span>
                </div>
            `;
        }

        updateCountdown();
        setInterval(updateCountdown, 1000);
    });
}",
